parameters.jsCode:
// ==== EXPECTATION ====
// Upstream Gmail node is "Get a thread" with Format = "full" and Return All Messages = true.

// ─── Inputs ───────────────────────────────────────────────────────────────────
const thread = items[0]?.json || {};
const msgs = Array.isArray(thread.messages) ? thread.messages : [];

// Optional webhook body (for intended recipients/sentAt hints)
let wb = {};
try { wb = $items('Webhook', 0, 0)[0]?.json?.body || {}; } catch { wb = {}; }

// Optional “Combine Payload” (where you store airtableRecordId/threadId)
const combine0 = (() => { try { return $items('Combine Payload', 0, 0)[0]?.json || {}; } catch { return {}; }})();

// ─── Config ───────────────────────────────────────────────────────────────────
const SENDER_EMAIL = 'placements.sv@scalevirtually.com';
const INTERNAL_DOMAINS = ['scalevirtually.com']; // tweak as needed

// ─── Helpers ──────────────────────────────────────────────────────────────────
const list = v => Array.isArray(v) ? v : (typeof v === 'string' ? v.split(/[,\s;]+/) : []);
const parseEmail = s => (String(s).match(/<([^>]+)>/)?.[1] || String(s)).trim().toLowerCase();
const isInternal = email => INTERNAL_DOMAINS.some(d => email.endsWith('@' + d.toLowerCase()));
const ms = m => { const t = m.internalDate ? Number(m.internalDate) : 0; return Number.isFinite(t) ? t : 0; };

function uniq(arr) { return Array.from(new Set(arr.filter(Boolean))); }
function without(arr, removeSet) { return arr.filter(x => !removeSet.has(x)); }

function getHeader(m, name) {
  if (!m?.payload?.headers) return '';
  const h = m.payload.headers.find(h => (h.name || '').toLowerCase() === name.toLowerCase());
  return h?.value || '';
}

// base64url → utf8
function b64urlToUtf8(b64url='') {
  try {
    const b64 = String(b64url).replace(/-/g, '+').replace(/_/g, '/');
    const pad = '='.repeat((4 - (b64.length % 4)) % 4);
    return Buffer.from(b64 + pad, 'base64').toString('utf8');
  } catch { return ''; }
}

// Walk Gmail payload tree to get body
function extractBodyFromPayload(payload) {
  if (!payload) return { text: '', html: '' };

  // single-part
  if (!payload.parts || !payload.parts.length) {
    const mime = (payload.mimeType || '').toLowerCase();
    const data = payload.body?.data ? b64urlToUtf8(payload.body.data) : '';
    if (/text\/plain/.test(mime)) return { text: data || '', html: '' };
    if (/text\/html/.test(mime))  return { text: '', html: data || '' };
    return { text: data || '', html: '' };
  }

  // multipart: prefer plain, fallback html
  let text = '', html = '';
  for (const p of payload.parts) {
    const child = extractBodyFromPayload(p);
    if (!text && child.text) text = child.text;
    if (!html && child.html) html = child.html;
    if (text && html) break;
  }
  return { text, html };
}

function htmlToText(html='') {
  return String(html)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/(p|div|li|tr)>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/\s+\n/g, '\n').replace(/[ \t]{2,}/g, ' ')
    .trim();
}

function b64urlFromUtf8(s) {
  return Buffer.from(s, 'utf8').toString('base64')
    .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/,'');
}

// ─── Strip quoted text + signatures ───────────────────────────────────────────
function stripQuotedAndSignatures(s='') {
  const lines = String(s).split('\n');
  const out = [];
  for (const ln of lines) {
    if (/^>+/.test(ln)) break;                          // quoted block
    if (/^On .+wrote:$/i.test(ln.trim())) break;        // Gmail quote header
    if (/^(From|Sent|To|Subject):/i.test(ln)) break;    // inline headers
    if (/^Sent from my (iPhone|Android)/i.test(ln)) break;
    out.push(ln);
  }
  let t = out.join('\n');
  t = t.replace(/This email.*?confidential[\s\S]{0,2000}$/i, '');
  return t.trim();
}

// ─── Build original To and Cc lists (headers are source of truth) ─────────────
const first = msgs[0] || {};
const firstTo = first.To || first.to || getHeader(first, 'to') || '';
const firstCc = first.Cc || first.cc || getHeader(first, 'cc') || '';

// 1) Start from the actual headers of the first message (your outbound)
let client_to = uniq(list(firstTo).map(parseEmail));
let client_cc = uniq(list(firstCc).map(parseEmail));

// 2) Only if headers are missing, fall back to webhook values
if (client_to.length === 0 && wb.to) {
  client_to = uniq(list(wb.to).map(parseEmail));
}
if (client_cc.length === 0 && wb.cc) {
  client_cc = uniq(list(wb.cc).map(parseEmail));
}

// 3) Never include our sender; and don't duplicate across To/Cc
const removeSet = new Set([parseEmail(SENDER_EMAIL)]);
client_to = without(client_to, removeSet);
client_cc = without(client_cc, removeSet);

// If an email is in To, remove it from Cc (preserve original roles)
const toSet = new Set(client_to);
client_cc = without(client_cc, toSet);

// Combined set used only for detecting client authors (not for addressing)
const recipientSet = new Set([...client_to, ...client_cc]);


// ─── Determine sentAt (fallback to earliest internal) ─────────────────────────
let sentAt = wb.sentAtIso ? new Date(wb.sentAtIso).getTime() : 0;
if (!Number.isFinite(sentAt) || sentAt <= 0) {
  const internalTimes = msgs
    .filter(m => isInternal(parseEmail(m.From || m.from || getHeader(m,'from') || '')))
    .map(ms).filter(t => t > 0);
  sentAt = internalTimes.length
    ? Math.min(...internalTimes)
    : (msgs.map(ms).filter(t => t > 0).sort((a,b)=>a-b)[0] || 0);
}

// ─── Identify latest reply from any original recipient (exclude internal) ─────
const fromIsClientRecipient = m => {
  const fromEmail = parseEmail(m.From || m.from || getHeader(m,'from') || '');
  return recipientSet.has(fromEmail) && !isInternal(fromEmail);
};

const replies = msgs
  .filter(fromIsClientRecipient)
  .map(m => ({ m, t: ms(m) }))
  .filter(x => x.t > sentAt)
  .sort((a,b) => b.t - a.t);

let latest = replies[0]?.m || null;

// ─── Extract body from the latest reply (if any) ──────────────────────────────
let body = '';
if (latest?.payload) {
  const { text, html } = extractBodyFromPayload(latest.payload);
  body = text || (html ? htmlToText(html) : '') || latest.snippet || '';
}
if (!body) body = '(no body text)';

// Clean up before heuristics
body = stripQuotedAndSignatures(body);
if (body.length > 4000) body = body.slice(0, 4000) + '…';
body = body.replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, m => m.toLowerCase());

// ─── Heuristic hint ───────────────────────────────────────────────────────────
const t = body.toLowerCase();
let hint = 'other', hint_conf = 0.0;
const yesPat = /\b(approved|let'?s proceed|go ahead|confirm(ed)?|confirmed|yes|ok(ay)?)\b/i;
const noPat  = /\b(cancel(l?ed|lation)?|not moving forward|decline|pass|reject(ed)?)\b/i;
const resPat = /\b(reschedul\w+|move (the )?time|another (time|day)|push back|can(?:'|no)t make|tomorrow|next (week|mon|tue|wed|thu|fri))\b/i;

// Treat "send the calendar invite" like approval (negation-aware)
const invitePat = /\b(send|share|shoot|send over)\s+(the\s+)?(calendar|cal|invite|zoom|meeting|calendar\s+invite)\b/i;
const negPat = /\b(do\s*not|don't|dont|no need to|no|not)\b/i;

if (yesPat.test(t)) { hint = 'approved';   hint_conf = 0.85; }
else if (noPat.test(t)) { hint = 'declined';   hint_conf = 0.85; }
else if (resPat.test(t)) { hint = 'reschedule'; hint_conf = 0.80; }

if (invitePat.test(t) && !negPat.test(t)) {
  hint = 'approved';
  hint_conf = Math.max(hint_conf, 0.90);
}

const date_time_hint = Array.from(new Set(
  body.match(/\b(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun|Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Sept|Oct|Nov|Dec)\b[^,\n]*?(?:\d{1,2})?(?:[^A-Za-z0-9]{1,6}\d{1,2}(?::\d{2})?\s*(?:am|pm)?)?/gi) || []
)).slice(0,5);

// ─── Fallback for follow-up (no client reply found) ───────────────────────────
let fallbackMsg = null;
if (!latest) {
  fallbackMsg = [...msgs]
    .filter(m => isInternal(parseEmail(m.From || m.from || getHeader(m,'from') || '')))
    .sort((a,b) => ms(b) - ms(a))[0] || null;
}

// Effective message for downstream (client reply if exists; else internal last)
const latestEffective = latest || fallbackMsg;

// ─── Build robust reply anchors ───────────────────────────────────────────────
const msg_api_id = latestEffective?.id || null;

let msg_rfc822_id = latestEffective
  ? getHeader(latestEffective, 'Message-ID') || getHeader(latestEffective, 'Message-Id') || null
  : null;

if (!msg_rfc822_id && first) {
  msg_rfc822_id =
    getHeader(first, 'Message-ID') ||
    getHeader(first, 'Message-Id') ||
    null;
}

const msg_snippet = latestEffective?.snippet
  ? String(latestEffective.snippet).slice(0, 200)
  : null;

const reply_anchor = msg_rfc822_id || msg_api_id || msg_snippet || '';

// ─── Detection block ──────────────────────────────────────────────────────────
const detection = {
  airtableRecordId: combine0.airtableRecordId,
  threadId: thread.id || combine0.threadId,
  client_replied: !!latest,
  last_client_reply_iso: latest ? new Date(ms(latest)).toISOString() : null,
  subject: first.Subject || first.subject || getHeader(first,'subject') || '',
  // preserve original addressing
  client_to,
  client_cc,
  client_recipients: uniq([...client_to, ...client_cc]),
  latest_client_msg_id: msg_api_id,
  message_rfc822_id: msg_rfc822_id,
  message_snippet: msg_snippet,
  reply_anchor
};

const llm_input = {
  subject: detection.subject,
  thread_id: detection.threadId,
  gmail_message_id: reply_anchor,
  reply_text: body,
  heuristic_hint: { label: hint, confidence: hint_conf, date_time_hint }
};

// ─── Compose follow-up content for sending into the thread ────────────────────
const FOLLOW_UP_TEXT =
  (combine0.follow_up_text || wb.followUpText || '') ||
  'Hi! Hope you’re doing well — just following up to see if you had a chance to review the candidates. Happy to answer any questions or propose interview times.';

// Build Subject
const subjectForSend = String(detection.subject || '').trim();
const replySubject = /^re:/i.test(subjectForSend) ? subjectForSend : `Re: ${subjectForSend}`;

// Build headers using preserved To / Cc
const toHeader = detection.client_to?.length ? detection.client_to.join(', ') : '';
const ccHeader = detection.client_cc?.length ? detection.client_cc.join(', ') : '';

// Build MIME with optional In-Reply-To/References
let mime =
  `From: ${SENDER_EMAIL}\r\n` +
  (toHeader ? `To: ${toHeader}\r\n` : '') +
  (ccHeader ? `Cc: ${ccHeader}\r\n` : '') +
  `Subject: ${replySubject}\r\n` +
  (detection.message_rfc822_id ? `In-Reply-To: ${detection.message_rfc822_id}\r\nReferences: ${detection.message_rfc822_id}\r\n` : '') +
  `Content-Type: text/plain; charset="UTF-8"\r\n` +
  `Content-Transfer-Encoding: 7bit\r\n` +
  `\r\n` +
  FOLLOW_UP_TEXT + `\r\n`;

const http_send_payload = {
  threadId: detection.threadId,
  raw: b64urlFromUtf8(mime)
};

// ─── Guard ────────────────────────────────────────────────────────────────────
if (!http_send_payload.threadId || !http_send_payload.raw) {
  return [{
    json: {
      ...detection,
      llm_input,
      error: "Missing send payload",
      needed: { threadId: !!http_send_payload.threadId, raw: !!http_send_payload.raw }
    }
  }];
}

// Final output
return [{
  json: {
    ...detection,
    llm_input,
    http_send_payload,
    preview_mime: mime
  }
}];

parameters.content:
Sends a follow-up message to the client and updates the record in Airtable. Loops back to waiting for 24 hours to check if the client replies. This will be an ongoing workflow until the client replies.

**Thread Id** = {{$json.threadId}} 
**Message Snippet or ID** = {{$json.reply_anchor}}
**CC** = {{ ($json.client_cc || []).filter(Boolean).join(',') }}

