// Code node (after Gmail "Get many messages")

function getRecordIdFromWebhook() {
  // Grab the first item from the Webhook node
  const wb = $items('Webhook', 0, 0)[0]?.json?.body || {};

  // 1) Direct field
  if (wb.airtableRecordId && /^rec[0-9A-Za-z]{14}$/.test(wb.airtableRecordId)) {
    return wb.airtableRecordId;
  }

  // 2) Fallback: parse from HTML comment <!-- rid: recXXXXXXXXXXXXXX -->
  const html = String(wb.body || '');
  const m = html.match(/rid:\s*(rec[0-9A-Za-z]{14})/i);
  if (m) return m[1];

  throw new Error('No Airtable Record ID found on Webhook payload.');
}

const recordId = getRecordIdFromWebhook();

// Attach recordId + Gmail IDs to each Gmail message item
return items.map(it => {
  const threadId = it.json.threadId ?? null;
  const messageId = it.json.id ?? it.json.messageId ?? null;

  return {
    json: {
      airtableRecordId: recordId,
      threadId,
      messageId,
      // keep original fields if you still need them downstream
      ...it.json,
    },
  };
});

// Purpose: From a batch of Gmail "Message → Get Many" or "Thread → Get" items,
// emit only the messages that (a) match the intended subject and (b) were sent
// to the target recipient in TO or CC. Works when the target was CC'd.
// Also returns: gmail_api_id, rfc822_message_id, threadId, date_iso.

// ---------- Inputs ----------
const wb = $node['Webhook'].json.body || {};
const targetSubjectRaw = String(wb.subject || '').trim();

// Prefer the webhook-provided target; otherwise fall back to a fixed address (edit as needed)
const defaultTarget = 'pj@scalevirtually.com';
const targetTo = String((Array.isArray(wb.to) ? wb.to[0] : wb.to) || defaultTarget).toLowerCase();

// ---------- Helpers ----------
function normSubject(s = '') {
  return String(s)
    .replace(/^\s*(re|fwd|fw)\s*:\s*/gi, '') // strip common prefixes
    .replace(/\s+/g, ' ')                    // collapse spaces
    .trim()
    .toLowerCase();
}

function normHeaders(msg) {
  const out = {};

  // 1) If headers is an array of { name, value }
  if (Array.isArray(msg.headers || msg.payload?.headers)) {
    const arr = msg.headers || msg.payload?.headers || [];
    for (const h of arr) {
      const k = String(h?.name || '').toLowerCase();
      const v = String(h?.value || '');
      out[k] = v;
    }
  }

  // 2) If headers is an object with "Subject: ..." style values
  if (msg.headers && !Array.isArray(msg.headers)) {
    for (const [k, v] of Object.entries(msg.headers)) {
      const key = String(k).toLowerCase();
      let val = String(v ?? '');
      if (key === 'subject') val = val.replace(/^subject:\s*/i, '');
      if (key === 'to')      val = val.replace(/^to:\s*/i, '');
      if (key === 'cc')      val = val.replace(/^cc:\s*/i, '');
      if (key === 'from')    val = val.replace(/^from:\s*/i, '');
      if (key === 'message-id' || key === 'messageid')
        val = val.replace(/^message-?id:\s*/i, '');
      if (key === 'date')    val = val.replace(/^date:\s*/i, '');
      out[key] = val;
    }
  }

  // 3) Fall back to top-level fields n8n provides
  const tl = {
    subject: msg.subject,
    date: msg.date,                 // ISO
    'message-id': msg.messageId,
    to:
      msg.to?.text ||
      msg.to?.html ||
      (Array.isArray(msg.to?.value) ? msg.to.value.map(v => v.address).join(', ') : ''),
    cc:
      msg.cc?.text ||
      msg.cc?.html ||
      (Array.isArray(msg.cc?.value) ? msg.cc.value.map(v => v.address).join(', ') : ''),
    from:
      msg.from?.text ||
      msg.from?.html ||
      (Array.isArray(msg.from?.value) ? msg.from.value.map(v => v.address).join(', ') : ''),
    'delivered-to': msg.headers?.['delivered-to'] || msg['delivered-to'],
  };
  for (const [k, v] of Object.entries(tl)) {
    if (v && !out[k]) out[k] = String(v);
  }

  // Cleanup
  for (const k of Object.keys(out)) out[k] = String(out[k]).trim();

  return out;
}

function extractEmails(s) {
  if (!s) return [];
  const emails = [];
  const re = /<?([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})>?/gi;
  let m;
  while ((m = re.exec(s))) emails.push(m[1].toLowerCase());
  if (!emails.length) {
    return s.split(',').map(x => x.trim().toLowerCase()).filter(Boolean);
  }
  return emails;
}

function normalizeRfc822Id(idRaw) {
  let id = String(idRaw || '').trim();
  if (!id) return '';
  if (!/^<.*>$/.test(id)) id = `<${id.replace(/^<|>$/g, '')}>`;
  return id;
}

// ---------- Filter & Map ----------
const inputItems = $input.all();
const out = [];

for (const it of inputItems) {
  const msg = it.json || {};
  const hdr = normHeaders(msg);

  // Subject check (case/spacing/Re/Fwd-insensitive)
  const subj = String(hdr['subject'] || '').trim();
  const subjMatch = targetSubjectRaw
    ? normSubject(subj) === normSubject(targetSubjectRaw)
    : true; // if no subject provided, don't filter by subject

  // Recipient check: TO + CC must contain target (or Delivered-To as fallback)
  const rcptLine = [hdr['to'], hdr['cc']].filter(Boolean).join(', ');
  const rcptList = extractEmails(rcptLine);

  const deliveredTo = extractEmails(hdr['delivered-to']).at(0); // helpful when parsing your own inbox
  const targets = new Set([targetTo, deliveredTo].filter(Boolean));
  const toOrCcMatch = rcptList.some(e => targets.has(e));

  if (subjMatch && toOrCcMatch) {
    const rfc822Id = normalizeRfc822Id(hdr['message-id'] || msg.messageId || '');
    out.push({
      json: {
        subject: subj,
        to: rcptList,
        gmail_api_id: msg.id || null,        // Gmail API message id (opaque)
        rfc822_message_id: rfc822Id || null, // RFC822 <...>
        threadId: msg.threadId || null,
        date_iso: msg.date || null
      }
    });
  }
}

return out;

// Combine Payload — NO reference to "Fetch Record ID"

// recordId from webhook (or from HTML comment fallback)
const wb = $items('Webhook', 0, 0)[0]?.json?.body || {};
const recordId =
  wb.airtableRecordId ||
  String(wb.body || '').match(/rid:\s*(rec[0-9A-Za-z]{14})/i)?.[1];

if (!recordId) throw new Error('No Airtable Record ID found from Webhook.');

// Gmail message (your previous node already narrowed to one item)
const msg = items[0].json;

// IDs
const gmailApiId = msg.id || msg.gmail_api_id || null;
const rfc822Id = msg.rfc822_message_id || msg['rfc822_message-id'] || null;

return [{
  json: {
    airtableRecordId: recordId,
    threadId: msg.threadId ?? null,
    messageId: gmailApiId,          // map this to Airtable "Message ID"
    gmail_api_id: gmailApiId,
    rfc822_message_id: rfc822Id,
    subject: msg.subject,
    to: msg.to,
    date_iso: msg.date_iso,
  }
}];

// Input: this item has llm_input.reply_text (from your Prep node)
const text = String($json.llm_input?.reply_text || '').trim();
const lower = text.toLowerCase();

// Patterns (tune/expand over time)
const reYes = /\b(approved|let'?s proceed|go ahead|confirmed|confirm(ed)?|we're good|sounds good|sgtm)\b/i;
const reNo  = /\b(cancel(l?ed|lation)?|not moving forward|won'?t proceed|decline|pass|reject(ed)?)\b/i;
const reRe  = /\b(reschedul\w+|another (time|day)|move|shift (the )?time|push back|can'?t make|cannot make|conflict|this (fri|mon|tue|wed|thu|saturday|sunday|monday|tuesday|wednesday|thursday|friday)|tomorrow|next (week|mon|tue|wed|thu|fri|sat|sun))\b/i;

// Extract date/time-ish phrases (verbatim)
const dt = Array.from(new Set(
  text.match(/\b(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun|Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday|Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Sept|Oct|Nov|Dec|today|tomorrow|this|next)\b[^,\n]*?(?:\d{1,2})?(?:[^A-Za-z0-9]{1,6}\d{1,2}(?::\d{2})?\s*(?:am|pm)?)?/gi) || []
)).map(s=>s.trim()).filter(Boolean).slice(0,8);

// Pick verbatim evidence line
function pickEvidence() {
  const lines = text.split(/\r?\n/).map(s => s.trim()).filter(Boolean);
  // prefer a line with strong cues
  return lines.find(s => reRe.test(s) || reNo.test(s) || reYes.test(s)) || lines[0] || text.slice(0,120);
}

let reply_status = 'Other'; // will decide below
let evidence = pickEvidence();

if (reRe.test(lower))       reply_status = 'Reschedule';
else if (reNo.test(lower))  reply_status = 'Declined';
else if (reYes.test(lower)) reply_status = 'Approved';

// Confidence: deterministic if matched, else 0
const confidence = reply_status === 'Other' ? 0 : 0.95;

// Output for IF branching
return [{
  json: {
    rule_status: reply_status,
    rule_confidence: confidence,
    evidence,
    dates_times: dt,
    // pass-through for later steps
    llm_input: $json.llm_input,
    threadId: $json.threadId,
    latest_client_msg_id: $json.latest_client_msg_id
  }
}];

